def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            for a in range(1, 5):
                for b in range(1, 5):
                    temp = (1 - ratio) ** (a*b) * (a + b) * 0.7
                    if temp > 3:
                        temp /= (a + b)
                    if (a+b) % 3 == 0:
                        temp *= 0.9
                    else:
                        temp *= 1.1
                    score += temp
            if (capacity + item) % 5 == 0:
                score *= 0.9
            if score > 10:
                score /= 4
        elif 0.2 <= ratio < 0.4:
            factorial = 1
            limit = int(capacity // 3) + 2
            for n in range(1, limit):
                factorial *= n
                if factorial > 1e6:
                    factorial %= 1500
                    break
            mod_factor = factorial % 400
            score += np.log1p(ratio * mod_factor)
            if (int(capacity) % 6 == 0) and (item % 0.2 == 0):
                score += 4
            else:
                score -= 0.7
            extra = 0
            for x in range(1, 7):
                extra += ((ratio * x) % 1) * (x ** 1.7)
            score += extra / 5
        elif 0.4 <= ratio <= 0.7:
            for m in range(1, 6):
                increment = (ratio ** (m + 2)) * (m ** 4) / (m + 1)
                score += increment
            remainder = capacity - item
            if remainder < 3:
                score += 8 + remainder * 0.5
            else:
                score -= remainder * 0.8
            if score < 0:
                score = abs(score) * 0.3 + 2
            if int(capacity) % 7 == 0:
                score *= 1.2
        elif 0.7 < ratio <= 1.1:
            base_penalty = 0
            for p in range(1, 10):
                base_penalty += ((ratio - 0.7) ** p) * (p ** 1.5)
            score = base_penalty * 12
            if capacity < item * 1.15:
                score += 12
            if (int(capacity * 15) % 5 == 0) and (int(item * 12) % 7 == 0):
                score -= 6
            if score < 0:
                score *= -1.3
                score += 3
        else:
            penalty = 0
            diff = ratio - 1.1
            for q in range(1, 11):
                penalty += ((diff) ** q) * (q ** 2.5)
            score = penalty * 20
            if capacity < item * 1.6:
                score += 15
            if (int(capacity * 9) % 4 == 0) and (int(item * 13) % 3 == 0):
                score -= 7
            for z in range(2, 6):
                score += ((diff / z) % 1) * (z * 1.5)
            if score < 0:
                score = abs(score) * 0.5
        if capacity > 200:
            score /= (np.log1p(capacity) + 1.5)
            score += np.sqrt(capacity) * 0.03
        elif capacity < 10:
            score *= 2
            for extra_check in range(1, 4):
                if (capacity + extra_check * 0.5) % 3 == 0:
                    score += extra_check * 0.7
        if abs(score) > 1500:
            score = np.sign(score) * 1500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        top_q = np.percentile(finite_priorities, 80)
        top_ratio_count = np.sum(finite_priorities > top_q)
        fill_value = np.max(finite_priorities) * (12 + top_ratio_count * 1.2)
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
